class Solution {
    public int[] numsSameConsecDiff(int n, int k) {
        int[] result = new int[n];
        int start = 10 * n + k;
        int end = start + (n - 1);

        for (int i = start; i <= end; i++) {
            result[i % 10] = i / 10;
        }

        return result;
    }
}
